 for i,v in enumerate(sum(g,[])):
  if v:d[v]=d.get(v,[])+[(i//10,i%10)]
 (c,s),(z,t)=d.items()
 if len(s)<len(t):c,s,z,t=z,t,c,s
 rb,cb=zip(*s)
 for dr in range(max(rb)-2,min(rb)+1):
  for dc in range(max(cb)-2,min(cb)+1):
   A={3*(r-dr)+c-dc for r,c in s}
   R={*range(9)}-A;u,v=t[0]
   for x in R:
    if{3*(r-(u-x//3))+c-(v-x%3)for r,c in t}==R:
     return[[(z,c)[i*3+j in A]for j in range(3)]for i in range(3)]
```

